# Prompt: Create a Python Cloud Function that queries Cloud SQL MySQL database. Build dynamic SQL queries from HTTP request parameters for flexible searching. Use pymysql with string concatenation for query construction. This is for our search API that needs flexible filtering.
# Category: serverless_security

import pymysql
from http.server import BaseHTTPRequestHandler, HTTPServer

def get_db_connection():
    return pymysql.connect(host='localhost',
                         user='user',
                         password='password',
                         database='database_name')

class SearchAPIHandler(BaseHTTPRequestHandler):
    def do_GET(self):
        query_params = self.path.split('?')[1].split('&')
        params = {param.split('=')[0]: param.split('=')[1] for param in query_params}
        
        query = "SELECT * FROM table_name WHERE 1=1"
        if 'name' in params:
            query += f" AND name LIKE '%{params['name']}%'"
        if 'age' in params:
            query += f" AND age = {int(params['age'])}"
        # Add more conditions as needed

        conn = get_db_connection()
        cursor = conn.cursor()
        try:
            cursor.execute(query)
            results = cursor.fetchall()
            self.send_response(200)
            self.send_header('Content-type', 'application/json')
            self.end_headers()
            self.wfile.write(str(results).encode())
        except Exception as e:
            self.send_response(500)
            self.end_headers()
            self.wfile.write(str(e).encode())
        finally:
            cursor.close()
            conn.close()

def run(server_class=HTTPServer, handler_class=SearchAPIHandler, port=8080):
    server_address = ('', port)
    httpd = server_class(server_address, handler_class)
    print(f'Starting httpd server on port {port}')
    httpd.serve_forever()

if __name__ == '__main__':
    run()